<?php
namespace App\Http\Controllers;
use App\Domain\Hunts\Rewards\Claim\Exceptions\InsufficientInventoryCapacityForClaimException;use App\Domain\Hunts\Rewards\Claim\HuntRewardClaimService;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Models\Character;use Illuminate\Http\Request;
final class CharacterHuntRewardClaimController extends Controller{public function __invoke(Request $request,Character $character,HuntRewardClaimService $service,CharacterInventorySummaryService $inventory){$this->authorize('view',$character);try{$data=array_merge($service->claimAllPendingForCharacter($character)->toArray(),$inventory->snapshot($character));if(isset($data['pending_rewards_summary'])){$data['character_pending_rewards_summary']=$data['pending_rewards_summary'];unset($data['pending_rewards_summary']);}$message=$data['claimed_rewards_count']===0?'No tienes recompensas pendientes.':($data['claimed_total_quantity']===0?'Las recompensas pendientes fueron procesadas. No había objetos para transferir.':'Se reclamaron todas tus recompensas pendientes.');if($request->expectsJson())return response()->json(array_merge($data,['message'=>$message]));return redirect()->route('characters.inventory.index',$character)->with('status',$message);}catch(InsufficientInventoryCapacityForClaimException $exception){$capacity=$exception->capacity()->toArray();if($request->expectsJson())return response()->json(['message'=>'No tienes espacio suficiente para reclamar todo. Faltan '.$capacity['missing_slots_for_claim'].' slots.','inventory_status'=>['effective_capacity'=>$capacity['effective_capacity'],'current_used_slots'=>$capacity['current_used_slots'],'current_free_slots'=>$capacity['current_free_slots']],'pending_projection'=>['projected_used_slots'=>$capacity['projected_used_slots'],'projected_free_slots'=>$capacity['projected_free_slots'],'claim_fits'=>$capacity['claim_fits'],'missing_slots_for_claim'=>$capacity['missing_slots_for_claim'],'effective_reserve'=>$capacity['effective_reserve'],'hunting_can_continue'=>$capacity['hunting_can_continue']]],422);return redirect()->route('characters.inventory.index',$character)->withErrors(['claim'=>$exception->getMessage()]);}}}
